import { type MutableRefObject, createContext, useContext } from 'react';

/**
 * @internal
 */
export interface ActionSelectionDetails {
  selectedItemId: string;
  actionsMenuRef: MutableRefObject<HTMLDivElement | null> | undefined;
  updateSelectedItem: (itemId: string) => void;
}

/**
 * @internal
 */
export const ActionSelectionContext = createContext<
  ActionSelectionDetails | undefined
>(undefined);

export const useActionSelection = () => {
  const context = useContext(ActionSelectionContext);
  if (context === undefined) {
    throw new Error(
      'useActionSelection must be used within ActionSelectionContext.Provider',
    );
  }
  return context;
};

ActionSelectionContext['displayName'] = 'ActionSelectionContext';
